targets.query:
from(bucket: "raw_bucket")
  |> range(start: v.timeRangeStart, stop: v.timeRangeStop)
  |> filter(fn: (r) => r._measurement == "raw_measurement" and r._field == "quality")
  |> group()
  |> reduce(identity: {good: 0.0, total: 0.0}, fn: (r, accumulator) => ({
       good: accumulator.good + (if r._value == "good" then 1.0 else 0.0),
       total: accumulator.total + 1.0,
     }))
  |> map(fn: (r) => ({ _value: if r.total > 0.0 then r.good / r.total * 100.0 else 0.0 }))
